SELECT count(*) FROM name, cast_info, aka_name, title, movie_keyword, keyword, role_type WHERE cast_info.person_id = name.id AND aka_name.person_id = name.id AND cast_info.movie_id = title.id AND movie_keyword.movie_id = title.id AND movie_keyword.keyword_id = keyword.id AND cast_info.role_id = role_type.id;